UPDATE bucket_account
SET frozen_balance = frozen_balance + #{amount},
    available_balance = available_balance - #{amount},
    updated_time = NOW(),
    version = version + 1
WHERE bucket_name = #{bucketName}
  AND version = #{version}
  AND available_balance >= #{amount}

UPDATE bucket_account
SET frozen_balance = frozen_balance - #{amount},
    available_balance = available_balance + #{amount},
    updated_time = NOW(),
    version = version + 1
WHERE bucket_name = #{bucketName}
  AND version = #{version}
  AND frozen_balance >= #{amount}
